const rows = $input.all();
const today = new Date();
const yesterday = new Date(today);
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toISOString().split('T')[0];

// Filter to yesterday's data
const todayRows = rows.filter(row => {
  const rowDate = row.json['Date'] || row.json['date'] || '';
  return rowDate.startsWith(dateStr);
});

const allRows = todayRows.length > 0 ? todayRows : rows; // fallback to all if no date match

let totalRevenue = 0;
let totalOrders = 0;
let totalUnits = 0;
const byRep = {};
const byProduct = {};

for (const row of allRows) {
  const revenue = parseFloat(row.json['Revenue'] || row.json['Amount'] || 0);
  const orders = parseInt(row.json['Orders'] || 1, 10);
  const units = parseInt(row.json['Units'] || 1, 10);
  const rep = row.json['Sales Rep'] || row.json['rep'] || 'Unknown';
  const product = row.json['Product'] || row.json['product'] || 'Other';

  totalRevenue += revenue;
  totalOrders += orders;
  totalUnits += units;

  byRep[rep] = (byRep[rep] || 0) + revenue;
  byProduct[product] = (byProduct[product] || 0) + revenue;
}

const topReps = Object.entries(byRep)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([name, rev]) => `<tr><td style="padding:6px 12px;">${name}</td><td style="padding:6px 12px; text-align:right;">$${rev.toLocaleString('en-US', {minimumFractionDigits:2})}</td></tr>`)
  .join('');

const topProducts = Object.entries(byProduct)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([name, rev]) => `<tr><td style="padding:6px 12px;">${name}</td><td style="padding:6px 12px; text-align:right;">$${rev.toLocaleString('en-US', {minimumFractionDigits:2})}</td></tr>`)
  .join('');

const avgOrderValue = totalOrders > 0 ? (totalRevenue / totalOrders) : 0;

const reportDate = yesterday.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

return [{
  json: {
    reportDate,
    dateStr,
    totalRevenue: totalRevenue.toFixed(2),
    totalOrders,
    totalUnits,
    avgOrderValue: avgOrderValue.toFixed(2),
    topRepsHtml: topReps,
    topProductsHtml: topProducts,
    rowCount: allRows.length
  }
}];
